import { Box, Card, CardContent, CircularProgress, FormControlLabel, Radio, Typography } from "@mui/material";
import React from "react";
import { formatMoney } from "../../utils/utils";

interface DeliveryCardProps {
    isLoadingCep: boolean;
    deliveryValue: number;
    deliveryForecast: number;
    bgColor?: string;
}

const DeliveryCard: React.FC<DeliveryCardProps> = ({ isLoadingCep, deliveryValue, deliveryForecast, bgColor = "white" }) => {

    return (
        <Card sx={{ bgcolor: bgColor }} elevation={3}>
            <CardContent>
                <Typography gutterBottom>
                    Preço e prazos
                </Typography>
                {isLoadingCep ?
                    <CircularProgress color="primary" />
                    :
                    <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                        <Typography color="text.secondary">
                            Entrega em até {deliveryForecast} dias úteis
                        </Typography>
                        <FormControlLabel
                            value="start"
                            control={<Radio />}
                            checked={true}
                            label={deliveryValue > 0 ? formatMoney(deliveryValue) : 'Grátis'}
                            labelPlacement="start"
                        />
                    </Box>
                }
            </CardContent>
        </Card>
    );
};

export default DeliveryCard;